import{_ as s,c as n,o as a,a4 as l}from"./chunks/framework.HaEZziQ1.js";const p="/FrontEndLearnNotes/assets/image-20240306172638946.BrqMti7v.png",e="/FrontEndLearnNotes/assets/image-20240306172745705.CIFzm2XC.png",o="/FrontEndLearnNotes/assets/image-20240306173039086.DybdHiMr.png",r="/FrontEndLearnNotes/assets/640.C-391lcx.png",c="/FrontEndLearnNotes/assets/640-1710253965396-38.FQ2rTTTg.png",t="/FrontEndLearnNotes/assets/640-1710253965396-39.R-BD5NSl.png",i="/FrontEndLearnNotes/assets/640-1710253965396-40.CLbJyvhC.png",v=JSON.parse('{"title":"CSS新特性","description":"","frontmatter":{},"headers":[],"relativePath":"Document/HTML和CSS/CSS/CSS新特性.md","filePath":"Document/HTML和CSS/CSS/CSS新特性.md","lastUpdated":1709727320000}'),B={name:"Document/HTML和CSS/CSS/CSS新特性.md"},y=l(`<h1 id="css新特性" tabindex="-1">CSS新特性 <a class="header-anchor" href="#css新特性" aria-label="Permalink to &quot;CSS新特性&quot;">​</a></h1><p><a href="https://moderncss.dev/" target="_blank" rel="noreferrer">现代 CSS 解决方案 --- Modern CSS Solutions</a></p><p>专栏：<a href="https://juejin.cn/column/7303816445040721983" target="_blank" rel="noreferrer">CSS之美 - 程普的专栏 - 掘金 (juejin.cn)</a></p><p>新的特性，最近发表的特性，对于旧版本的浏览器或者部分浏览器不支持，或者不兼容，酌情使用</p><p>HTML+CSS+JavaScript兼容性查询网站：<a href="https://caniuse.com/ciu/about" target="_blank" rel="noreferrer">Can I use... Support tables for HTML5, CSS3, etc</a></p><p>可以快速可视化哪些前端技术与哪些浏览器兼容</p><p>直接从CanIUse网站查看支持表外，还有一个为喜欢命令行工具的用户提供的选项。这个设置非常简单。首先，您需要确保安装了Node.js，它是npm预打包的。要检查是否已经安装了npm，只需在CLI中运行npm -v。</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">npm</span><span style="color:#98C379;"> install</span><span style="color:#D19A66;"> -g</span><span style="color:#98C379;"> caniuse-cmd</span></span>
<span class="line"><span style="color:#61AFEF;">caniuse</span><span style="color:#98C379;"> preload</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="https://www.11meigui.com/wp-content/uploads/2020/03/caniuse-preload-1024x50.png" alt="caniuse-preload"></p><p>还有许多选项可以根据个人喜好和所需的信息来使用。这些内容包括:</p><p>—short， -s short输出:一行显示浏览器，不显示注释或描述<a href="./布尔值">显示多个结果时默认</a></p><p>—long， -l long输出:显示更多信息<a href="./布尔值">显示单个结果时的默认值</a></p><p>—oneline， -1单行输出:只有全局百分比，没有每个浏览器的信息</p><hr><p><strong>CSS</strong> 的<strong>2019-2022年</strong>的新特性发展状态报告：</p><p><a href="https://2019.stateofcss.com/tw/" target="_blank" rel="noreferrer">The State of CSS 2019</a></p><p><a href="https://2020.stateofcss.com/zh-Hans/" target="_blank" rel="noreferrer">The State of CSS 2020</a></p><p><a href="https://2021.stateofcss.com/zh-Hans/" target="_blank" rel="noreferrer">The State of CSS 2021</a></p><p><a href="https://2022.stateofcss.com/en-US/" target="_blank" rel="noreferrer">The State of CSS 2022</a></p><hr><p>CSS新特性文章参考：</p><p>2017：</p><ul><li><p><a href="https://juejin.cn/post/6844903480100913166" target="_blank" rel="noreferrer">2017 年值得学习的 3 个 CSS 新特性 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/6844903518931795982" target="_blank" rel="noreferrer">css3新特性汇总 - 掘金 (juejin.cn)</a></p></li></ul><p>2019：</p><ul><li><p><a href="https://juejin.cn/post/6844903829679390728" target="_blank" rel="noreferrer">CSS3 和 HTML5 新特性一览 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/6844904033149255688" target="_blank" rel="noreferrer">2019年这1年多学到的CSS新特性 | 掘金年度征文 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/6844904033870675981" target="_blank" rel="noreferrer">CSS3 新特性 - 掘金 (juejin.cn)</a></p></li></ul><p>2020：</p><ul><li><a href="https://zhuanlan.zhihu.com/p/267066908" target="_blank" rel="noreferrer">2020不容错过！24个CSS新特性来了 - 知乎 (zhihu.com)</a></li></ul><p>2021：</p><ul><li><p><a href="https://blog.csdn.net/Taobaojishu/article/details/120574222" target="_blank" rel="noreferrer">详解16个CSS新特性（2021最新版-下）</a></p></li><li><p><a href="https://juejin.cn/post/6886258269137043464" target="_blank" rel="noreferrer">超详|2020年你不应该错过的CSS新特性 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/7007336931092594701" target="_blank" rel="noreferrer">一起了解一下css新特性@property - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://www.gxlsystem.com/qianduan-8992.html" target="_blank" rel="noreferrer">5个你已经可以尝试的css新特性 (gxlsystem.com)</a></p></li><li><p><a href="https://juejin.cn/post/6958990366888607757" target="_blank" rel="noreferrer">CSS新特性contain，控制页面的重绘与重排 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/6978647140910727176" target="_blank" rel="noreferrer">2021年你可能不知道的 CSS 特性（下篇） - 掘金 (juejin.cn)</a></p></li></ul><p>2022：</p><ul><li><p><a href="https://blog.csdn.net/weixin_47426048/article/details/125594552" target="_blank" rel="noreferrer">2022年你不知道的CSS新特性_wei佳的博客-CSDN博客_css 2022新特性</a></p></li><li><p><a href="https://juejin.cn/post/7108549853969383455" target="_blank" rel="noreferrer">2022年CSS的6个新特性，赶快来了解一下（看过就会的那种） - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/7073291417728057381" target="_blank" rel="noreferrer">2022年你不应该错过的CSS新特性 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/7103409377821851662" target="_blank" rel="noreferrer">2022年你不知道的CSS新特性 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/7118892686861402120" target="_blank" rel="noreferrer">都2022年了，还不知道这几个CSS特性该out了 - 掘金 (juejin.cn)</a></p></li><li><p><a href="https://juejin.cn/post/7334755783751794724" target="_blank" rel="noreferrer">全新的 CSS 语法，2024新年新样式 - 掘金 (juejin.cn)</a></p></li></ul><h2 id="css-变量" tabindex="-1">CSS 变量 <a class="header-anchor" href="#css-变量" aria-label="Permalink to &quot;CSS 变量&quot;">​</a></h2><h3 id="一、变量的声明" tabindex="-1">一、变量的声明 <a class="header-anchor" href="#一、变量的声明" aria-label="Permalink to &quot;一、变量的声明&quot;">​</a></h3><p>声明变量的时候，变量名前面要加两根连词线（<code>--</code>）。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">body</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --foo</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#7F583F</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --bar</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#F7EFD2</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>上面代码中，<code>body</code>选择器里面声明了两个变量：<code>--foo</code>和<code>--bar</code>。</p><p>它们与<code>color</code>、<code>font-size</code>等正式属性没有什么不同，只是没有默认含义。所以 CSS 变量（CSS variable）又叫做**&quot;CSS 自定义属性&quot;**（CSS custom properties）。因为变量与自定义的 CSS 属性其实是一回事。</p><p>你可能会问，为什么选择两根连词线（<code>--</code>）表示变量？因为<code>$foo</code>被 Sass 用掉了，<code>@foo</code>被 Less 用掉了。为了不产生冲突，官方的 CSS 变量就改用两根连词线了。</p><p>各种值都可以放入 CSS 变量。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">:root</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#E06C75;">  --main-color</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#4d4e53</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --main-bg</span><span style="color:#ABB2BF;">: </span><span style="color:#56B6C2;">rgb</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E06C75;">  --logo-border-color</span><span style="color:#ABB2BF;">: rebeccapurple;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E06C75;">  --header-height</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">68</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --content-padding</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">10</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 20</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E06C75;">  --base-line-height</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">1.428571429</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --transition-duration</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">.35</span><span style="color:#E06C75;">s</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --external-link</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;external link&quot;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --margin-top</span><span style="color:#ABB2BF;">: </span><span style="color:#56B6C2;">calc</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">2</span><span style="color:#E06C75;">vh</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> 20</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>变量名大小写敏感，<code>--header-color</code>和<code>--Header-Color</code>是两个不同变量。</p><h3 id="二、var-函数" tabindex="-1">二、var() 函数 <a class="header-anchor" href="#二、var-函数" aria-label="Permalink to &quot;二、var() 函数&quot;">​</a></h3><p><code>var()</code>函数用于读取变量。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--foo</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-decoration-color: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--bar</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>var()</code>函数还可以使用第二个参数，表示变量的默认值。如果该变量不存在，就会使用这个默认值。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">color: var(--foo</span><span style="color:#ABB2BF;">,</span><span style="color:#FFFFFF;"> #7F583F</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第二个参数不处理内部的逗号或空格，都视作参数的一部分。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">var(--font-stack</span><span style="color:#ABB2BF;">,</span><span style="color:#C678DD;"> &quot;Roboto&quot;</span><span style="color:#ABB2BF;">,</span><span style="color:#C678DD;"> &quot;Helvetica&quot;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">var(--pad</span><span style="color:#ABB2BF;">,</span><span style="color:#C678DD;"> 10px 15px 20px</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>var()</code>函数还可以用在变量的声明。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">:root</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --primary-color</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">red</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --logo-text</span><span style="color:#ABB2BF;">: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--primary-color</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>注意，变量值只能用作属性值，不能用作属性名。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.foo</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --side</span><span style="color:#ABB2BF;">: margin-top;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* 无效 */</span></span>
<span class="line"><span style="color:#ABB2BF;">  var(</span><span style="color:#E06C75;">--side</span><span style="color:#ABB2BF;">): </span><span style="color:#D19A66;">20</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>上面代码中，变量<code>--side</code>用作属性名，这是无效的。</p><h3 id="三、变量值的类型" tabindex="-1">三、变量值的类型 <a class="header-anchor" href="#三、变量值的类型" aria-label="Permalink to &quot;三、变量值的类型&quot;">​</a></h3><p>如果变量值是一个字符串，可以与其他字符串拼接。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">--bar: &#39;hello&#39;;</span></span>
<span class="line"><span style="color:#C678DD;">--foo: var(--bar</span><span style="color:#ABB2BF;">)&#39; </span><span style="color:#C678DD;">world&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>利用这一点，可以 debug（<a href="https://codepen.io/malyw/pen/oBWMOY" target="_blank" rel="noreferrer">例子</a>）。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">body</span><span style="color:#56B6C2;">:after</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  content: </span><span style="color:#98C379;">&#39;--screen-category : &#39;</span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--screen-category</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果变量值是数值，不能与数值单位直接连用。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.foo</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --gap</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">20</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* 无效 */</span></span>
<span class="line"><span style="color:#ABB2BF;">  margin-top: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--gap</span><span style="color:#ABB2BF;">)px;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>上面代码中，数值与单位直接写在一起，这是无效的。必须使用<code>calc()</code>函数，将它们连接。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.foo</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --gap</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">20</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  margin-top: </span><span style="color:#56B6C2;">calc</span><span style="color:#ABB2BF;">(</span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--gap</span><span style="color:#ABB2BF;">) </span><span style="color:#56B6C2;">*</span><span style="color:#D19A66;"> 1</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果变量值带有单位，就不能写成字符串。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">/* 无效 */</span></span>
<span class="line"><span style="color:#D19A66;">.foo</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --foo</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&#39;20px&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  font-size: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--foo</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">/* 有效 */</span></span>
<span class="line"><span style="color:#D19A66;">.foo</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --foo</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">20</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  font-size: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--foo</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="四、作用域" tabindex="-1">四、作用域 <a class="header-anchor" href="#四、作用域" aria-label="Permalink to &quot;四、作用域&quot;">​</a></h3><p>同一个 CSS 变量，可以在多个选择器内声明。读取的时候，优先级最高的声明生效。这与 CSS 的&quot;层叠&quot;（cascade）规则是一致的。</p><p>下面是一个<a href="http://jsbin.com/buwahixoqo/edit?html,css,output" target="_blank" rel="noreferrer">例子</a>。</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">style</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#56B6C2;">  :root</span><span style="color:#ABB2BF;"> { </span><span style="color:#E06C75;">--color</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">; }</span></span>
<span class="line"><span style="color:#E06C75;">  div</span><span style="color:#ABB2BF;"> { </span><span style="color:#E06C75;">--color</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">green</span><span style="color:#ABB2BF;">; }</span></span>
<span class="line"><span style="color:#61AFEF;">  #alert</span><span style="color:#ABB2BF;"> { </span><span style="color:#E06C75;">--color</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">red</span><span style="color:#ABB2BF;">; }</span></span>
<span class="line"><span style="color:#E06C75;">  *</span><span style="color:#ABB2BF;"> { color: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--color</span><span style="color:#ABB2BF;">); }</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">style</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">p</span><span style="color:#ABB2BF;">&gt;蓝色&lt;/</span><span style="color:#E06C75;">p</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;绿色&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">div</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;alert&quot;</span><span style="color:#ABB2BF;">&gt;红色&lt;/</span><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>上面代码中，三个选择器都声明了<code>--color</code>变量。不同元素读取这个变量的时候，会采用优先级最高的规则，因此三段文字的颜色是不一样的。</p><p>这就是说，变量的作用域就是它所在的选择器的有效范围。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">body</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --foo</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#7F583F</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">.content</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --bar</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#F7EFD2</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>上面代码中，变量<code>--foo</code>的作用域是<code>body</code>选择器的生效范围，<code>--bar</code>的作用域是<code>.content</code>选择器的生效范围。</p><p>由于这个原因，全局的变量通常放在根元素<code>:root</code>里面，确保任何选择器都可以读取它们。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">:root</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --main-color</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#06c</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="五、响应式布局" tabindex="-1">五、响应式布局 <a class="header-anchor" href="#五、响应式布局" aria-label="Permalink to &quot;五、响应式布局&quot;">​</a></h3><p>CSS 是动态的，页面的任何变化，都会导致采用的规则变化。</p><p>利用这个特点，可以在响应式布局的<code>media</code>命令里面声明变量，使得不同的屏幕宽度有不同的变量值。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">body</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  --primary</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#7F583F</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">  --secondary</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#F7EFD2</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--primary</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-decoration-color: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--secondary</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">@media</span><span style="color:#ABB2BF;"> screen </span><span style="color:#56B6C2;">and</span><span style="color:#ABB2BF;"> (min-width: </span><span style="color:#D19A66;">768</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E06C75;">  body</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">    --primary</span><span style="color:#ABB2BF;">:  </span><span style="color:#D19A66;">#F7EFD2</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E06C75;">    --secondary</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">#7F583F</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="六、兼容性处理" tabindex="-1">六、兼容性处理 <a class="header-anchor" href="#六、兼容性处理" aria-label="Permalink to &quot;六、兼容性处理&quot;">​</a></h3><p>对于不支持 CSS 变量的浏览器，可以采用下面的写法。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">#7F583F</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#56B6C2;">var</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">--primary</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>也可以使用<code>@support</code>命令进行检测。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">@supports</span><span style="color:#ABB2BF;"> ( (</span><span style="color:#E06C75;">--a</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">)) {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* supported */</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">@supports</span><span style="color:#ABB2BF;"> ( </span><span style="color:#56B6C2;">not</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">--a</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">)) {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* not supported */</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="七、javascript-操作" tabindex="-1">七、JavaScript 操作 <a class="header-anchor" href="#七、javascript-操作" aria-label="Permalink to &quot;七、JavaScript 操作&quot;">​</a></h3><p>JavaScript 也可以检测浏览器是否支持 CSS 变量。</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> isSupported</span><span style="color:#56B6C2;"> =</span></span>
<span class="line"><span style="color:#E5C07B;">  window</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">CSS</span><span style="color:#56B6C2;"> &amp;&amp;</span></span>
<span class="line"><span style="color:#E5C07B;">  window</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">CSS</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">supports</span><span style="color:#56B6C2;"> &amp;&amp;</span></span>
<span class="line"><span style="color:#E5C07B;">  window</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">CSS</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">supports</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;--a&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">isSupported</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* supported */</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">else</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  /* not supported */</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>JavaScript 操作 CSS 变量的写法如下。</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// 设置变量</span></span>
<span class="line"><span style="color:#E5C07B;">document</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">body</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">style</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">setProperty</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;--primary&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;#7F583F&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 读取变量</span></span>
<span class="line"><span style="color:#E5C07B;">document</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">body</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">style</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getPropertyValue</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;--primary&#39;</span><span style="color:#ABB2BF;">).</span><span style="color:#61AFEF;">trim</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// &#39;#7F583F&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 删除变量</span></span>
<span class="line"><span style="color:#E5C07B;">document</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">body</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">style</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">removeProperty</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;--primary&#39;</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这意味着，JavaScript 可以将任意值存入样式表。下面是一个监听事件的例子，事件信息被存入 CSS 变量。</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> docStyle</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> document</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">documentElement</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">style</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">document</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">addEventListener</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;mousemove&#39;</span><span style="color:#ABB2BF;">, (</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  docStyle.setProperty(</span><span style="color:#98C379;">&#39;--mouse-x&#39;</span><span style="color:#ABB2BF;">, e.clientX);</span></span>
<span class="line"><span style="color:#ABB2BF;">  docStyle.setProperty(</span><span style="color:#98C379;">&#39;--mouse-y&#39;</span><span style="color:#ABB2BF;">, e.clientY);</span></span>
<span class="line"><span style="color:#ABB2BF;">});</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>那些对 CSS 无用的信息，也可以放入 CSS 变量。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">--foo: if(x 5</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">this</span><span style="color:#D19A66;">.width</span><span style="color:#C678DD;"> = 10;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>上面代码中，<code>--foo</code>的值在 CSS 里面是无效语句，但是可以被 JavaScript 读取。这意味着，可以把样式设置写在 CSS 变量中，让 JavaScript 读取。</p><p>所以，CSS 变量提供了 JavaScript 与 CSS 通信的一种途径。</p><h2 id="css属性" tabindex="-1">CSS属性 <a class="header-anchor" href="#css属性" aria-label="Permalink to &quot;CSS属性&quot;">​</a></h2><h3 id="in-range-和-out-of-range-伪类" tabindex="-1">:in-range 和:out-of-range 伪类 <a class="header-anchor" href="#in-range-和-out-of-range-伪类" aria-label="Permalink to &quot;:in-range 和:out-of-range 伪类&quot;">​</a></h3><p>CSS的<code>:in-range</code>和<code>:out-of-range</code>伪类用于样式化在指定范围限制内和外的输入。</p><h4 id="a-in-range" tabindex="-1">(a) :in-range <a class="header-anchor" href="#a-in-range" aria-label="Permalink to &quot;(a) :in-range&quot;">​</a></h4><p>如果输入元素的当前值在 <code>min</code> 和 <code>max</code> 属性的范围之间，那么它就处于范围内。</p><p>这个伪类可以方便地确定字段的当前值是否可接受。</p><h4 id="b-out-of-range" tabindex="-1">(b) :out-of-range <a class="header-anchor" href="#b-out-of-range" aria-label="Permalink to &quot;(b) :out-of-range&quot;">​</a></h4><p>如果输入元素的当前值超出了<code>min</code>和<code>max</code>属性的范围，那么它就是超出范围的。</p><p>它给用户一个视觉指示，告诉他们字段值是否超出了范围。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">/* in-range */</span></span>
<span class="line"><span style="color:#E06C75;">input</span><span style="color:#56B6C2;">:in-range</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">background-color: </span><span style="color:#56B6C2;">rgba</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0.25</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">/* out-of-range */</span></span>
<span class="line"><span style="color:#E06C75;">input</span><span style="color:#56B6C2;">:out-of-range</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">background-color: </span><span style="color:#56B6C2;">rgba</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0.25</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><img src="`+p+`" alt="image-20240306172638946"></p><p>注意：这些伪类只适用于具有范围限制的元素，没有这个限制，元素就无法处于范围内或范围外。</p><p>相关文档：<a href="https://developer.mozilla.org/en-US/docs/Web/CSS/:in-range" target="_blank" rel="noreferrer">:in-range - CSS: Cascading Style Sheets | MDN (mozilla.org)</a></p><h3 id="_2-grayscale-函数-2-grayscale-函数" tabindex="-1">2. grayscale() 函数 2. grayscale（）函数 <a class="header-anchor" href="#_2-grayscale-函数-2-grayscale-函数" aria-label="Permalink to &quot;2. grayscale() 函数 2. grayscale（）函数&quot;">​</a></h3><p>如果使用<code>0</code>到<code>100%</code>之间的值，可以创建不同的效果。较低的值将保留一些颜色，而较高的值将使图像更接近黑白。</p><p>这种图像效果可以通过CSS的滤镜属性实现。通过将图像的<code>filter</code>属性设置为<code>grayscale(100%)</code>，可以将图像完全转换为黑白。要创建不同的效果，可以尝试不同的<code>grayscale</code>值，例如<code>grayscale(50%)</code>将使图像呈现一种半色调效果。</p><p>使用CSS的图像转换效果，可以通过调整值来轻松地将彩色图像转换为黑白，并实现各种不同的效果。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.grayscale-image</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  filter: </span><span style="color:#56B6C2;">grayscale</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+e+`" alt="image-20240306172745705"></p><h3 id="_3-玻璃效果" tabindex="-1">3. 玻璃效果 <a class="header-anchor" href="#_3-玻璃效果" aria-label="Permalink to &quot;3. 玻璃效果&quot;">​</a></h3><p>我们可以使用几行代码实现一个玻璃效果。玻璃效果非常美丽，可以为我们的设计增添优雅。</p><p><a href="https://css.glass/" target="_blank" rel="noreferrer">Glass.CSS</a>是最受欢迎的玻璃效果生成器，我们可以免费为项目创建CSS玻璃效果。只需要根据您的需求调整一些设置，并将CSS代码复制粘贴到您的项目中即可。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.glass-effect</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#56B6C2;">   -webkit-backdrop-filter</span><span style="color:#ABB2BF;">: </span><span style="color:#56B6C2;">blur</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">6.2</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">   backdrop-filter: </span><span style="color:#56B6C2;">blur</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">6.2</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">   background: </span><span style="color:#56B6C2;">rgba</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0.4</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">   border-radius: </span><span style="color:#D19A66;">16</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">   border: </span><span style="color:#D19A66;">1</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> solid</span><span style="color:#56B6C2;"> rgba</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0.24</span><span style="color:#ABB2BF;">); </span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="_4-使用以下css代码来样式化文本" tabindex="-1">4.使用以下CSS代码来样式化文本 <a class="header-anchor" href="#_4-使用以下css代码来样式化文本" aria-label="Permalink to &quot;4.使用以下CSS代码来样式化文本&quot;">​</a></h2><p>这些是一些每个人都应该知道的非常基本的文本样式技巧。然而，还有许多其他高级选项可供选择。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">p</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  font-family: </span><span style="color:#D19A66;">Helvetica</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">Arial</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">sans-serif</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  font-size: </span><span style="color:#D19A66;">5</span><span style="color:#E06C75;">rem</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-transform: </span><span style="color:#D19A66;">capitalize</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-shadow: </span><span style="color:#D19A66;">2</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 2</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 2</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;"> pink, </span><span style="color:#D19A66;">1</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 1</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 2</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;"> pink;</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-align: </span><span style="color:#D19A66;">center</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  font-weight: </span><span style="color:#D19A66;">normal</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  line-height: </span><span style="color:#D19A66;">1.6</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  letter-spacing: </span><span style="color:#D19A66;">2</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="_5-clamp-函数" tabindex="-1">5.clamp() 函数 <a class="header-anchor" href="#_5-clamp-函数" aria-label="Permalink to &quot;5.clamp() 函数&quot;">​</a></h2><p>CSS的<code>clamp()</code>函数将一个值限制在两个上下界之间。必须有一个首选值、一个最小值和一个最大值。</p><p>当字体大小根据视口变化时，<code>clamp()</code> 会派上用场。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">p</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  font-size: </span><span style="color:#56B6C2;">clamp</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">1.8</span><span style="color:#E06C75;">rem</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">2.5</span><span style="color:#E06C75;">vw</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">2.8</span><span style="color:#E06C75;">rem</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="_6-居中一个-div" tabindex="-1">6. 居中一个 div <a class="header-anchor" href="#_6-居中一个-div" aria-label="Permalink to &quot;6. 居中一个 div&quot;">​</a></h2><p>开发者最重要的任务之一是将一个<code>div</code>居中。有很多其他的选项可以实现div的居中。在这个例子中，我们使用CSS的<code>flexbox</code>来实现<code>div</code>的水平和垂直居中。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  display: </span><span style="color:#D19A66;">flex</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  justify-content: </span><span style="color:#D19A66;">center</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  align-items: </span><span style="color:#D19A66;">center</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="_7-css线性渐变" tabindex="-1">7. CSS线性渐变 <a class="header-anchor" href="#_7-css线性渐变" aria-label="Permalink to &quot;7. CSS线性渐变&quot;">​</a></h2><p>要创建一个渐变的CSS线性渐变，只需使用下面的CSS代码。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">    background: </span><span style="color:#56B6C2;">linear-gradient</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">35</span><span style="color:#E06C75;">deg</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">#CCFFFF</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">#FFCCCC</span><span style="color:#ABB2BF;">, </span><span style="color:#56B6C2;">rgb</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">204</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">204</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">255</span><span style="color:#ABB2BF;">));</span></span>
<span class="line"><span style="color:#ABB2BF;">    border-radius: </span><span style="color:#D19A66;">20</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    width: </span><span style="color:#D19A66;">70</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    height: </span><span style="color:#D19A66;">400</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">    margin: </span><span style="color:#D19A66;">50</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> auto</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="_8-css抖动效果" tabindex="-1">8. CSS抖动效果 <a class="header-anchor" href="#_8-css抖动效果" aria-label="Permalink to &quot;8. CSS抖动效果&quot;">​</a></h2><p>这个“摇晃”动画效果会在用户输入无效内容时晃动输入框。它简单而优雅。例如，如果用户在文本框中输入数字而不是字母，输入框将会摇晃。</p><div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">input</span><span style="color:#D19A66;"> id</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;name&quot;</span><span style="color:#D19A66;"> type</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;text&quot;</span><span style="color:#D19A66;"> placeholder</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;Enter your name&quot;</span><span style="color:#D19A66;"> pattern</span><span style="color:#ABB2BF;">=</span><span style="color:#98C379;">&quot;[A-Za-z]*&quot;</span><span style="color:#ABB2BF;">/&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">input:invalid{</span></span>
<span class="line"><span style="color:#ABB2BF;">      animation: shake 0.2s ease-in-out 0s 2;</span></span>
<span class="line"><span style="color:#ABB2BF;">      box-shadow: 0 0 0.4em red;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#ABB2BF;">  @keyframes shake {</span></span>
<span class="line"><span style="color:#ABB2BF;">      0% { margin-left: 0rem; }</span></span>
<span class="line"><span style="color:#ABB2BF;">      25% { margin-left: 0.5rem; }</span></span>
<span class="line"><span style="color:#ABB2BF;">      75% { margin-left: -0.5rem; }</span></span>
<span class="line"><span style="color:#ABB2BF;">      100% { margin-left: 0rem; }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="_9-文本溢出" tabindex="-1">9. 文本溢出 <a class="header-anchor" href="#_9-文本溢出" aria-label="Permalink to &quot;9. 文本溢出&quot;">​</a></h2><p>可以使用此属性来截断溢出的文本。它可以被裁剪并显示为省略号<code>(...)</code>或自定义字符串。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.text</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  white-space: </span><span style="color:#D19A66;">nowrap</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  overflow: </span><span style="color:#D19A66;">hidden</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-overflow: </span><span style="color:#D19A66;">clip</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  width: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;"> }</span></span>
<span class="line"><span style="color:#E06C75;">div</span><span style="color:#D19A66;">.text</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  white-space: </span><span style="color:#D19A66;">nowrap</span><span style="color:#ABB2BF;">; </span></span>
<span class="line"><span style="color:#ABB2BF;">  width: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">; </span></span>
<span class="line"><span style="color:#ABB2BF;">  overflow: </span><span style="color:#D19A66;">hidden</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-overflow: </span><span style="color:#D19A66;">ellipsis</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  border: </span><span style="color:#D19A66;">1</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> solid</span><span style="color:#D19A66;"> #000000</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}  </span></span>
<span class="line"><span style="color:#E06C75;">div</span><span style="color:#D19A66;">.text</span><span style="color:#56B6C2;">:hover</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  overflow: </span><span style="color:#D19A66;">visible</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h2 id="_10-column-count-属性" tabindex="-1">10. &#39;column-count&#39; 属性 <a class="header-anchor" href="#_10-column-count-属性" aria-label="Permalink to &quot;10. &#39;column-count&#39; 属性&quot;">​</a></h2><p>它指定了一个元素应该被分成的列数。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">p</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  column-count: </span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="_11-css动画" tabindex="-1">11. CSS动画 <a class="header-anchor" href="#_11-css动画" aria-label="Permalink to &quot;11. CSS动画&quot;">​</a></h2><p>动画逐渐改变元素的样式。只有在指定关键帧之后才能使用。关键帧描述了动画序列中特定点上动画元素的外观。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  width: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  height: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  background-color: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  animation-name: </span><span style="color:#D19A66;">square</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  animation-duration: </span><span style="color:#D19A66;">8</span><span style="color:#E06C75;">s</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#C678DD;">@keyframes</span><span style="color:#E06C75;font-style:italic;"> square</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  from {background-color: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">;}</span></span>
<span class="line"><span style="color:#ABB2BF;">  to {background-color: </span><span style="color:#D19A66;">black</span><span style="color:#ABB2BF;">;}</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="_12-阴影效果" tabindex="-1">12. 阴影效果 <a class="header-anchor" href="#_12-阴影效果" aria-label="Permalink to &quot;12. 阴影效果&quot;">​</a></h2><p>使用CSS，我们可以为文本和元素添加效果。将属性定义为<code>text-shadow</code>和<code>box-shadow</code>。使用<code>text-shadow</code>为文本添加阴影，使用box-shadow为元素添加阴影。</p><p>(i) <code>text-shadow</code>: It gives the text a shadow. (i) <code>text-shadow</code>: 它给文本添加了阴影。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">h1</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  text-shadow: </span><span style="color:#D19A66;">2</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 2</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 4</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> #000000</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>box-shadow</code>：用于给元素添加阴影效果。下面的示例中，实际的 <code>div</code> 元素是紫色的，盒子阴影是天蓝色的，并且设置在右下方 <code>10</code> 像素处。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  width: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  height: </span><span style="color:#D19A66;">200</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  padding: </span><span style="color:#D19A66;">15</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  background-color: </span><span style="color:#D19A66;">purple</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  box-shadow: </span><span style="color:#D19A66;">10</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> 10</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;"> skyblue;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="_13-css剪裁" tabindex="-1">13. CSS剪裁 <a class="header-anchor" href="#_13-css剪裁" aria-label="Permalink to &quot;13. CSS剪裁&quot;">​</a></h2><p>使用<code>clip-path</code>属性，您可以仅显示元素的一部分，同时隐藏其余部分。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#D19A66;">.bg</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">  height: </span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  width: </span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  background-color: </span><span style="color:#56B6C2;">rgba</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">199</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">62</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">133</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0.9</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  clip-path: </span><span style="color:#56B6C2;">polygon</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">100</span><span style="color:#E06C75;">%</span><span style="color:#D19A66;"> 51</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#D19A66;"> 100</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#D19A66;"> 90</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#D19A66;"> 52</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">0</span><span style="color:#D19A66;"> 51</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  position: </span><span style="color:#D19A66;">absolute</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="_14-css-背景混合模式属性" tabindex="-1">14.CSS 背景混合模式属性 <a class="header-anchor" href="#_14-css-背景混合模式属性" aria-label="Permalink to &quot;14.CSS 背景混合模式属性&quot;">​</a></h2><p>该属性描述了背景颜色和图像（或两个图像）的混合方式。一个与每个背景图像对应的混合模式列表组成了该值。混合模式指定了背景图层如何混合（颜色或图片）。</p><p>可以使用<code>background-blend-mode</code>属性创建令人惊艳的背景。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">div</span><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#ABB2BF;">   width: </span><span style="color:#D19A66;">600</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">   height: </span><span style="color:#D19A66;">400</span><span style="color:#E06C75;">px</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">   background-repeat: </span><span style="color:#D19A66;">no-repeat</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">repeat</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">   background-position: </span><span style="color:#D19A66;">center</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">   background-image: </span><span style="color:#56B6C2;">url</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;flower.png&quot;</span><span style="color:#ABB2BF;">), </span><span style="color:#56B6C2;">url</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&quot;background-image.png&quot;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">   background-blend-mode: </span><span style="color:#D19A66;">color</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><img src="`+o+`" alt="image-20240306173039086"></p><h2 id="_15-色相旋转动画" tabindex="-1">15. 色相旋转动画 <a class="header-anchor" href="#_15-色相旋转动画" aria-label="Permalink to &quot;15. 色相旋转动画&quot;">​</a></h2><p>还有其他一些选项可供选择。如果你想了解更多关于这个属性的信息，<a href="https://www.w3schools.com/cssref/pr_background-blend-mode.php" target="_blank" rel="noreferrer">请在W3Schools上查看</a>。</p><p>可以在网站的主要部分和按钮上添加色相旋转动画。例如，天气预报网站的主要部分将因此而变得令人惊艳。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E06C75;">button</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  background: </span><span style="color:#56B6C2;">linear-gradient</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">35</span><span style="color:#E06C75;">deg</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">#8C52FF</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">#C669FF</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  animation: hue-rotate </span><span style="color:#D19A66;">3</span><span style="color:#E06C75;">s</span><span style="color:#D19A66;"> linear</span><span style="color:#D19A66;"> infinite</span><span style="color:#D19A66;"> alternate</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#C678DD;">@keyframes</span><span style="color:#E06C75;font-style:italic;"> hue-rotate</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  to {</span></span>
<span class="line"><span style="color:#ABB2BF;">    filter: </span><span style="color:#56B6C2;">hue-rotate</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">85</span><span style="color:#E06C75;">deg</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;"> }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="css整洁之道——-is-、-where-和-has-的用法" tabindex="-1">CSS整洁之道——:is()、:where()和:has()的用法 <a class="header-anchor" href="#css整洁之道——-is-、-where-和-has-的用法" aria-label="Permalink to &quot;CSS整洁之道——:is()、:where()和:has()的用法&quot;">​</a></h2><p>让我们写出优雅界面的CSS，它也总是把自己进化得更加优雅。</p><p>今天我们花5分钟时间学习三个优雅的CSS伪类：<strong><code>:is()</code></strong>、<strong><code>:where()</code></strong> 和 <strong><code>:has()</code></strong>。</p><h3 id="is-取代组合选择器" tabindex="-1"><code>:is()</code> - 取代组合选择器 <a class="header-anchor" href="#is-取代组合选择器" aria-label="Permalink to &quot;\`:is()\` - 取代组合选择器&quot;">​</a></h3><p><strong><code>:is()</code></strong> 允许你在一个规则中包含多个选择器。它接受一组选择器作为参数，并应用样式到匹配的元素上。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">/* 传统方法 */</span></span>
<span class="line"><span style="color:#E06C75;">ul</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> li</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> a</span><span style="color:#ABB2BF;">,</span><span style="color:#C678DD;"> </span></span>
<span class="line"><span style="color:#E06C75;">ol</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> li</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> a</span><span style="color:#ABB2BF;">,</span><span style="color:#C678DD;"> </span></span>
<span class="line"><span style="color:#E06C75;">nav</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> ul</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> li</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> a</span><span style="color:#ABB2BF;">,</span><span style="color:#C678DD;"> </span></span>
<span class="line"><span style="color:#E06C75;">nav</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> ol</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> li</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> a</span><span style="color:#ABB2BF;"> { </span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">; </span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">/* 使用 :is() */</span></span>
<span class="line"><span style="color:#56B6C2;">:is</span><span style="color:#C678DD;">(</span><span style="color:#E06C75;">ul</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> ol</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> nav</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> ul</span><span style="color:#ABB2BF;">,</span><span style="color:#E06C75;"> nav</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> ol</span><span style="color:#C678DD;">) </span><span style="color:#ABB2BF;">&gt;</span><span style="color:#E06C75;"> li</span><span style="color:#ABB2BF;"> &gt;</span><span style="color:#E06C75;"> a</span><span style="color:#ABB2BF;"> { </span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">; </span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong><code>:is()</code></strong> 可以简化多层嵌套和多种选择器组合的写法，让你维护样式更方便。</p><p><strong><code>:is()</code></strong> 优先级依然遵循CSS选择器的优先级规则，即 <code>ID -&gt; 类 -&gt; 元素</code> 的顺序。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">:is</span><span style="color:#C678DD;">(</span><span style="color:#D19A66;">.class1</span><span style="color:#C678DD;">) </span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">blue</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#56B6C2;">:is</span><span style="color:#C678DD;">(</span><span style="color:#61AFEF;">#id1</span><span style="color:#C678DD;">) </span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">red</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这段代码里两条规则如果命中相同的元素，那么第二条会优先应用。</p><p><strong><code>:is()</code></strong> 的参数也可以传一个匹配规则</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">:is</span><span style="color:#C678DD;">([</span><span style="color:#D19A66;">class</span><span style="color:#ABB2BF;">^=</span><span style="color:#98C379;">&quot;is-styling&quot;</span><span style="color:#C678DD;">]) </span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">yellow</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这样的写法会匹配所有 <strong><code>class</code></strong> 开头是 <strong><code>is-styling</code></strong> 的选择器。</p><h3 id="where-拥有最低优先级" tabindex="-1"><code>:where()</code> - 拥有最低优先级 <a class="header-anchor" href="#where-拥有最低优先级" aria-label="Permalink to &quot;\`:where()\` - 拥有最低优先级&quot;">​</a></h3><p><strong><code>:where()</code></strong> 和 <strong>:is()</strong> 相似，都可以传入选择器或者匹配规则来简化你的CSS代码。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">:where</span><span style="color:#C678DD;">([</span><span style="color:#D19A66;">class</span><span style="color:#ABB2BF;">^=</span><span style="color:#98C379;">&quot;where-styling&quot;</span><span style="color:#C678DD;">]) </span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">yellow</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>但和 <strong>:is()</strong> 不同的是，<strong><code>:where()</code></strong> 拥有最低优先级，这样的好处是它定义的样式规则不会影响其他样式规则，避免了样式冲突。</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">/* &lt;footer class=&quot;where-styling&quot;&gt;……&lt;/footer&gt; */</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E06C75;">footer</span><span style="color:#E06C75;"> a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">green</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#56B6C2;">:where</span><span style="color:#C678DD;">([</span><span style="color:#D19A66;">class</span><span style="color:#ABB2BF;">^=</span><span style="color:#98C379;">&quot;where-styling&quot;</span><span style="color:#C678DD;">]) </span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  color: </span><span style="color:#D19A66;">red</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>当有其他规则和 <strong><code>:where()</code></strong> 同时被命中时，<strong><code>:where()</code></strong> 一定是失效的。所以上面这个例子实际效果是链接显示绿色。</p><h3 id="has-基于其他元素进行匹配" tabindex="-1"><code>:has()</code> - 基于其他元素进行匹配 <a class="header-anchor" href="#has-基于其他元素进行匹配" aria-label="Permalink to &quot;\`:has()\` - 基于其他元素进行匹配&quot;">​</a></h3><p><strong><code>:has()</code></strong> 可以根据直接后代元素的存在来匹配元素</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">/* 选择直接包含 p 元素的 div */</span></span>
<span class="line"><span style="color:#E06C75;">div</span><span style="color:#56B6C2;">:has</span><span style="color:#C678DD;">(</span><span style="color:#ABB2BF;">&gt;</span><span style="color:#E06C75;"> p</span><span style="color:#C678DD;">)</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  border: </span><span style="color:#D19A66;">1</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> solid</span><span style="color:#D19A66;"> black</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>也可以根据紧邻的下一个兄弟元素来匹配元素</p><div class="language-css line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">/* 选择后面跟着 p 元素的 div */</span></span>
<span class="line"><span style="color:#E06C75;">div</span><span style="color:#56B6C2;">:has</span><span style="color:#C678DD;">(</span><span style="color:#ABB2BF;">+</span><span style="color:#E06C75;"> p</span><span style="color:#C678DD;">)</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#ABB2BF;">  border: </span><span style="color:#D19A66;">1</span><span style="color:#E06C75;">px</span><span style="color:#D19A66;"> solid</span><span style="color:#D19A66;"> black</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>你还可以把它跟其他伪类一起使用，比如 <strong><code>:has()</code></strong> 和 <strong><code>:is()</code></strong> 一起使用</p><p><a href="https://code.juejin.cn/pen/7314946185520201763" target="_blank" rel="noreferrer">:has()和:is()一起使用 - 码上掘金 (juejin.cn)</a></p><p><strong><code>:has()</code></strong> 使用场景很多，只要是强互动的页面都可能用到，以后有机会单独分享一篇～</p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>大部分浏览器的新版本都已支持 <strong><code>:is()</code></strong>、 <strong><code>:where()</code></strong> 和 <strong><code>:has()</code></strong> 这三个伪类了，如果你的项目跑在低版本的浏览器中，那么需要考虑一下回退策略。</p><h2 id="_2023年的css" tabindex="-1">2023年的CSS <a class="header-anchor" href="#_2023年的css" aria-label="Permalink to &quot;2023年的CSS&quot;">​</a></h2><p><a href="https://developer.chrome.com/blog/css-wrapped-2023?hl=zh-cn" target="_blank" rel="noreferrer">CSS 封装：2023 年！ | Blog | Chrome for Developers</a></p><h3 id="众望所归的-css-嵌套和-css-父选择器正式落地" tabindex="-1">众望所归的 CSS 嵌套和 CSS 父选择器正式落地 <a class="header-anchor" href="#众望所归的-css-嵌套和-css-父选择器正式落地" aria-label="Permalink to &quot;众望所归的 CSS 嵌套和 CSS 父选择器正式落地&quot;">​</a></h3><p>今年除了 JavaScript 以外，CSS 也同样迎来了一系列新特性，这些特性不仅增强了样式和布局的能力，还提升了开发者的效率和用户体验。下面笔者仅介绍个人认为比较重要的两个 CSS 新特性，具体更多新特性的详情可以参考文章：<a href="https://mp.weixin.qq.com/s?__biz=MjM5MTA1MjAxMQ==&amp;mid=2651268063&amp;idx=1&amp;sn=275d824d73102d0dbf743efb8ce126cd&amp;chksm=bd48fa5b8a3f734da9e0f87e75530cf0e06b865fbab4a2f81cc8127387f67fabc635df3110a4&amp;scene=21#wechat_redirect" target="_blank" rel="noreferrer">【第3144期】2023年CSS新特性盘点</a></p><h3 id="_1、原生-css-支持嵌套" tabindex="-1">1、原生 CSS 支持嵌套 <a class="header-anchor" href="#_1、原生-css-支持嵌套" aria-label="Permalink to &quot;1、原生 CSS 支持嵌套&quot;">​</a></h3><p>CSS 支持嵌套一直是 Sass 中最受开发者喜爱的功能点之一，它允许让开发者在编写样式的时候更加整洁、内聚。据上一年 State of CSS 统计，CSS 嵌套是受访者认为 CSS 最需要补充的功能之一。</p><p><img src="`+r+'" alt="图片"></p><p>（图选自 <a href="https://2023.stateofcss.com/zh-Hans/usage/#what_do_you_use_css_for%EF%BC%89" target="_blank" rel="noreferrer">https://2023.stateofcss.com/zh-Hans/usage/#what_do_you_use_css_for）</a></p><p>而在今年 CSS 2023 新特性中，原生 CSS 正式支持嵌套写法，在高版本浏览器中，无需依赖额外的编译器即可享受 Sass 嵌套语法，很大程度上优化了开发者体验，提高了CSS 的可读性和可维护性。</p><p><img src="'+c+'" alt="图片">（图选自<a href="https://mp.weixin.qq.com/s?__biz=MjM5MTA1MjAxMQ==&amp;mid=2651268063&amp;idx=1&amp;sn=275d824d73102d0dbf743efb8ce126cd&amp;chksm=bd48fa5b8a3f734da9e0f87e75530cf0e06b865fbab4a2f81cc8127387f67fabc635df3110a4&amp;scene=21#wechat_redirect" target="_blank" rel="noreferrer">【第3144期】2023年CSS新特性盘点</a>）</p><h3 id="_2、各大浏览器正式支持-css-父选择器" tabindex="-1">2、各大浏览器正式支持 CSS 父选择器 <a class="header-anchor" href="#_2、各大浏览器正式支持-css-父选择器" aria-label="Permalink to &quot;2、各大浏览器正式支持 CSS 父选择器&quot;">​</a></h3><p>除了 CSS 嵌套外，父选择器也是受访者认为 CSS 最需要补充的功能之一。简单来说，CSS 父选择器的作用能通过子元素选中其父元素。既然是万众期待且如此实用的选择器，为什么各大浏览器迟迟没有支持呢？</p><p><img src="'+t+'" alt="图片"></p><p>（图选自 <a href="https://2023.stateofcss.com/zh-Hans/usage/#what_do_you_use_css_for%EF%BC%89" target="_blank" rel="noreferrer">https://2023.stateofcss.com/zh-Hans/usage/#what_do_you_use_css_for）</a></p><p>笔者总结答案主要是以下两个原因：</p><ol><li>浏览器的渲染模式是以流的方式，一个元素接一个元素进入。因此当一个元素在浏览器渲染出来时，其父元素的样式计算已经完成并且也已经渲染好了。在此之后，通过子元素选择父元素并应用样式触发重绘时，需要对父元素和子元素都进行重新绘制，这样的计算对于当时的渲染引擎而言是昂贵的。</li><li>与其他选择器而言，父选择器触发重绘的性能开销很大，如果有一个父选择器，那将很容易成为低效率选择器中的新老大。</li></ol><p>近几年浏览器的渲染引擎有了很大的改进，目前浏览器可以有效地确定哪些需要渲染或更新，而哪些不需要。因此在今年众望所归的父选择器 :has 也正式被各大浏览器所支持。</p><p><img src="'+i+'" alt="图片"></p><p>（图选自<a href="https://mp.weixin.qq.com/s?__biz=MjM5MTA1MjAxMQ==&amp;mid=2651268063&amp;idx=1&amp;sn=275d824d73102d0dbf743efb8ce126cd&amp;chksm=bd48fa5b8a3f734da9e0f87e75530cf0e06b865fbab4a2f81cc8127387f67fabc635df3110a4&amp;scene=21#wechat_redirect" target="_blank" rel="noreferrer">【第3144期】2023年CSS新特性盘点</a>）</p><p>参考内容：</p><p>CSS 的父选择器:has()：<a href="https://www.w3cplus.com/css/css-parent-selector.html" target="_blank" rel="noreferrer">https://www.w3cplus.com/css/css-parent-selector.html</a></p><p>CSS 原生嵌套语法来了！ - 知乎：<a href="https://zhuanlan.zhihu.com/p/603168988" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/603168988</a></p>',211),d=[y];function b(u,A,m,F,C,h){return a(),n("div",null,d)}const S=s(B,[["render",b]]);export{v as __pageData,S as default};
